-- ============================================================n-- 007_guests_table.sqln-- Guest list management: track RSVPs, dietary restrictions, groupsn-- ============================================================nn-- ------------------------------------------------------------n-- Enumsn-- ------------------------------------------------------------nCREATE TYPE guest_group AS ENUM ('bride_family', 'groom_family', 'bridal_party', 'friends', 'other');nCREATE TYPE rsvp_status AS ENUM ('pending', 'yes', 'no', 'maybe');nn-- ------------------------------------------------------------n-- Tablesn-- ------------------------------------------------------------nCREATE TABLE guests (n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),n  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),n  couple_id UUID NOT NULL REFERENCES couples(id) ON DELETE CASCADE,n  name TEXT NOT NULL,n  phone TEXT, -- E.164 format, e.g., +16135550123n  email TEXT,n  rsvp_status rsvp_status NOT NULL DEFAULT 'pending',n  rsvp_guest_count INT NOT NULL DEFAULT 0, -- number of guests including selfn  dietary_restrictions TEXT,n  plus_one BOOLEAN NOT NULL DEFAULT false,n  plus_one_name TEXT,n  group_tag guest_group NOT NULL DEFAULT 'other',n  notes TEXT,n  conversation_id UUID REFERENCES conversations(id) ON DELETE SET NULLn);nnCREATE TABLE audit_logs (n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),n  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),n  couple_id UUID REFERENCES couples(id) ON DELETE CASCADE,n  event_type TEXT NOT NULL, -- 'message_classified', 'message_sent', 'message_escalated', etc.n  resource_type TEXT NOT NULL, -- 'message', 'guest', 'phone_number', etc.n  resource_id UUID, -- optional reference to the affected resource
  metadata JSONB, -- flexible data storage for event detailsn  error_message TEXT -- for failed operationsn);nn-- ------------------------------------------------------------n-- Row Level Securityn-- ------------------------------------------------------------nALTER TABLE guests ENABLE ROW LEVEL SECURITY;nALTER TABLE audit_logs ENABLE ROW LEVEL SECURITY;nn-- ------------------------------------------------------------n-- RLS policies for guestsn-- ------------------------------------------------------------nCREATE POLICY "guests: own rows only"n  ON guestsn  FOR ALLn  USING (n    EXISTS (n      SELECT 1 FROM couplesn      WHERE couples.id = guests.couple_idn        AND (auth.jwt() ->> 'sub') = couples.clerk_user_idn    )n  )n  WITH CHECK (n    EXISTS (n      SELECT 1 FROM couplesn      WHERE couples.id = guests.couple_idn        AND (auth.jwt() ->> 'sub') = couples.clerk_user_idn    )n  );nn-- ------------------------------------------------------------n-- RLS policies for audit_logs (couples can view their own logs)n-- ------------------------------------------------------------nCREATE POLICY "audit_logs: own rows only"n  ON audit_logsn  FOR SELECTn  USING (n    EXISTS (n      SELECT 1 FROM couplesn      WHERE couples.id = audit_logs.couple_idn        AND (auth.jwt() ->> 'sub') = couples.clerk_user_idn    )n  );nn-- ------------------------------------------------------------n-- Indexesn-- ------------------------------------------------------------nCREATE INDEX idx_guests_couple_id ON guests(couple_id);nCREATE INDEX idx_guests_phone ON guests(phone);nCREATE INDEX idx_guests_rsvp_status ON guests(rsvp_status);nCREATE INDEX idx_guests_group_tag ON guests(group_tag);nCREATE INDEX idx_audit_logs_couple_id ON audit_logs(couple_id);nCREATE INDEX idx_audit_logs_event_type ON audit_logs(event_type);nCREATE INDEX idx_audit_logs_created_at ON audit_logs(created_at);nn-- ------------------------------------------------------------n-- Trigger to update updated_at on guests tablen-- ------------------------------------------------------------nCREATE OR REPLACE FUNCTION update_updated_at_column()nRETURNS TRIGGER AS $$nBEGINn  NEW.updated_at = now();n  RETURN NEW;nEND;n$$ language 'plpgsql';nnCREATE TRIGGER update_guests_updated_atn  BEFORE UPDATE ON guestsn  FOR EACH ROWn  EXECUTE FUNCTION update_updated_at_column();n